module sub(.Q(q), .C(c), .D(d));
endmodule

wire q_out;
sub reg_inst(.Q(q_out), .C(clk), .D(din));
assign output_sig = reg_inst;

module top #(parameter CTRL = 0) (
  input  clk,
  output out_sig
);
  generate
    if (CTRL) begin
      assign out_sig = clk;
    end else begin
      assign out_sig = ~clk;
    end
  endgenerate
endmodule
